// SPEC QFLUSH QS3 — state.ts
// Rôle : Registry centralisé de l’état des process supervisés.
export class QsStateRegistry {
    map = new Map();
    get(name) {
        return this.map.get(name);
    }
    set(info) {
        this.map.set(info.name, info);
    }
    update(name, patch) {
        const prev = this.map.get(name);
        if (!prev)
            return;
        const merged = { ...prev, ...patch };
        this.map.set(name, merged);
    }
    list() {
        return Array.from(this.map.values());
    }
}
